1	import { _decorator, log, Node, Vec3 } from "cc";
2	import GameView from "../GameView";
3	import { FLY_EVENT } from "../FlyManager";
4	import { BaseState, eventManager, stateManager } from "db://astarte-framework/Managers";
5	import Game_Define from "../Game_Define";
6	import { FEATURE_WHEEL_EVENT } from "../FeatureWheel/FeatureWheelManager";
7	import { FeatureWheelSegmentType, FEATURE_WHEEL_SEGMENT_COUNT, SpinResult } from "../FeatureWheel/FeatureWheelTypes";
8	import { FEATURE_MARK_EVENT } from "../FeatureWheel/FeatureMarkEvent";
9	import { JP_EVENT, JP_Type } from "../JP/JP_Define";
10	import { SHAKE_EVENT } from "../ShakeManager";
11	import { REEL_MANAGER_EVENT } from "../ReelManager";
12	import { ar2es2Proto } from "@igs-arcade-division-rd2/uk_872_eyestrike2_proto";
13	import { Define } from "db://astarte-framework/utilis";
14	
15	const { ccclass } = _decorator;
16	
17	/**
18	 * @ch Feature Wheel 轉輪演出 State（骨架 + 轉輪，不含落點後盤面效果）
19	 *
20	 * 位置：plate0 的 AWARD（對線獎）之後、ROUND_SHOW_END 之前（由 GameView.AfterShowWin 守衛導向）。
21	 * 對應規格 3.1 STEP3-5「檢查轉輪 → 觸發轉輪 → 第一次發動」；重轉（STEP6）仍為後續 plate。
22	 *
23	 * 職責邊界（scope = 骨架+轉輪演出）：
24	 *   IN  — SHOW_UI → 依 WheelFeatures 逐項 PLAY_SPIN(SlotIndex) 序列等待 → HIDE_UI → ROUND_SHOW_END
25	 *   OUT — 落點後的盤面演出（符號轉 CASH / 乘倍 badge / 升級 / FG 交棒）由後續 plate 停輪或後續階段處理
26	 *
27	 * 不在此 State 改動狀態機路由：FG（Type=0/4）的實際進場仍走既有 CheckState/LeaveRespin 的 IsGoingToFree。
28	 */
29	@ccclass( "FeatureWheelShowState" )
30	export class FeatureWheelShowState extends BaseState
31	{
32	    //#region 進場盤面效果參數（震動 + 盤面往下；需配合畫面實測微調）
33	    /**
34	     * @ch 盤面位移量（傳給 ZOOM_IN_REEL 的 targetLocalPos）。
35	     * ⚠️ ZoomInReel 公式：targetPos = 原座標 − targetLocalPos×scale → y 取「正」時盤面往「下」。
36	     *    動的是 GetZoomTarget()（GameView 整體），實際位移幅度需看畫面微調；BigWheel 若為其子節點會一起被移動。
37	     */
38	    private static readonly BOARD_ZOOM_POS = new Vec3( 0, 40, 0 );
39	
40	    /**@ch 盤面縮放（1 = 只位移不放大；>1 會放大整個 GameView）*/
41	    private static readonly BOARD_ZOOM_SCALE = 1.2;
42	
43	    /**@ch 盤面往下（ZoomIn）動畫時長（秒）*/
44	    private static readonly BOARD_ZOOM_IN_DURATION = 0.2;
45	
46	    /**@ch 盤面還原（ZoomOut）動畫時長（秒）*/
47	    private static readonly BOARD_ZOOM_OUT_DURATION = 0.2;
48	    //#endregion
49	    
50	    /**@ch 落點顯示停留時間（秒）*/
51	    private static readonly RESULT_STAY_DURATION = 1;
52	    
53	    /**@ch 停留時間（秒）*/
54	    private static readonly STAY_DURATION = 0.8;
55	
56	    private m_gameView: GameView = null;
57	
58	    constructor( gameView: GameView )
59	    {
60	        super();
61	        this.m_gameView = gameView;
62	    }
63	
64	    public async OnEnter()
65	    {
66	        log( "OnEnter State : FEATURE_WHEEL_SHOW" );
67	
68	        // 只取「有效」轉輪項（Type≠None）。理論上進到此 State 必有 ≥1（AfterShowWin 已用 HasActiveWheel 守衛），
69	        // 此處再過濾一次防禦：把混在其中的 None 項剔除，避免無意義轉動。
70	        const features = ( this.m_gameView.RoundInfo?.WheelFeatures ?? [] )
71	            .filter( w => w != null && w.Type !== FeatureWheelSegmentType.None );
72	
73	        if ( features.length === 0 )
74	        {
75	            // 不應發生（守衛已擋）；fail-loud 但不炸狀態機，直接續流程
76	            console.warn( "[FeatureWheelShowState] 無有效 WheelFeatures，跳過轉輪演出" );
77	            stateManager.NextState( Game_Define.GameState.ROUND_SHOW_END );
78	            return;
79	        }
80	
81	        // 進場盤面效果：震動只在進場「震一下就停」（單次自停，避免轉動時持續晃很怪）；盤面往下(ZoomIn)持續整段、退場才還原。
82	        // 用 try/finally 保證 StopBoardEffect 一定執行（ZoomIn 記原始狀態，未配對盤面回不去）。
83	        this.StartBoardEffect();
84	        try
85	        {
86	            // 進場 Active（盤面下降+灰塵+光效）：一個 round 一次，落在第一次轉動前；await 播畢（Spine 缺失則立即返回不 hang）
87	            await this.PlayWheelEnter();
88	
89	            // WheelCount 迴圈：逐項「序列等待」——PlaySpin 有 m_isSpinning 重入守衛，
90	            // 未等前一次 callback 就發下一次會被靜默丟棄（FeatureWheelManager 行為，BC-2 硬約束）。
91	            for ( const wf of features )
92	            {
93	                const landIndex = wf.SlotIndex ?? 0;
94	
95	                // 防 hang：PlaySpin 對越界 landIndex 是 warn+return（不呼叫 callback）→ 若 await 會永久掛住。
96	                // 故在 dispatch 前先驗範圍，越界則 fail-loud 跳過該次（不 await）。
97	                if ( landIndex < 0 || landIndex >= FEATURE_WHEEL_SEGMENT_COUNT )
98	                {
99	                    console.warn( `[FeatureWheelShowState] SlotIndex=${landIndex} 越界 0~${FEATURE_WHEEL_SEGMENT_COUNT - 1}，跳過該次轉動` );
100	                    continue;
101	                }
102	
103	                const result = await this.PlaySpinOnce( landIndex );
104	
105	                // fail-loud 一致性：落點 type 應與 server WheelFeatures.Type 相符
106	                // （前提 P：server SlotIndex 與客戶端 12 格序一致——待 server 對拍；不符僅 warn 不阻流程）
107	                if ( result != null && result.type !== wf.Type )
108	                {
109	                    console.warn( `[FeatureWheelShowState] 落點 type 不一致：landed=${result.type} vs server=${wf.Type}（SlotIndex=${landIndex}）` );
110	                }
111	                
112	                // 落點顯示停留時間
113	                await Define.Wait( this.m_gameView, FeatureWheelShowState.RESULT_STAY_DURATION );
114	
115	                // 飛個效果下來到盤面指定位置
116	                await this.PlayFlyEffect( wf );
117	
118	                // ②標記 seam：通知演出端在盤面標記此功能（標記/icon/乘倍/Grand報獎/FreeGame盤外 由同事 handler 渲染）。
119	                await this.PlayMarkEffect( wf );
120	
121	                // 落點顯示已由 BigWheel Collect 動畫（PlaySpin 內 await）負責，中間維持亮起至退場 Out；
122	                // 故不再需要結果展示牌的暫代 dwell 與 HIDE_RESULT。
123	            }
124	
125	            // ③轉換 seam：標記後、進 respin 前，套用符號轉換（一般符號→CASH）。fire-and-forget；演出由同事 handler 渲染。
126	            const transferResult = this.m_gameView.RoundInfo?.TransferResult ?? [];
127	            if ( transferResult.length > 0 )
128	            {
129	                await this.PlaySymbolTransferEffect( transferResult );
130	            }
131	
132	            // 退場 Out（盤面回歸+中間功能暗掉）：等全部轉動與效果（含 transfer）演完才播，一個 round 一次
133	            await this.PlayWheelExit();
134	        }
135	        finally
136	        {
137	            // 停留一下再收尾
138	            await Define.Wait( this.m_gameView, FeatureWheelShowState.STAY_DURATION );
139	
140	            // 盤面效果收尾：停震動 + 還原 ZoomIn（await 還原完成，盤面回正後才續流程）。
141	            // 放 finally 確保即使上面拋例外也會停震動/還原盤面，不卡死畫面。
142	            await this.StopBoardEffect();
143	        }
144	
145	        eventManager.Dispatch( FEATURE_WHEEL_EVENT.RESUME_IDLE );
146	
147	        stateManager.NextState( Game_Define.GameState.ROUND_SHOW_END );
148	    }
149	
150	    /**
151	     * @ch 啟動進場盤面效果：單次全畫面震動（SHAKE，播完自停）+ 盤面往下（ZoomIn）。fire-and-forget，與 Active 同時。
152	     * 震動單次自停、不需配對；ZoomIn 記原始狀態，須與 StopBoardEffect 的 RESTORE 配對（由 OnEnter try/finally 保證）。
153	     */
154	    private StartBoardEffect()
155	    {
156	        eventManager.Dispatch( SHAKE_EVENT.SHAKE_WITH_NAME, "feature_wheel_active" );
157	        eventManager.Dispatch(
158	            REEL_MANAGER_EVENT.ZOOM_IN_REEL,
159	            FeatureWheelShowState.BOARD_ZOOM_POS,
160	            FeatureWheelShowState.BOARD_ZOOM_SCALE,
161	            FeatureWheelShowState.BOARD_ZOOM_IN_DURATION
162	        );
163	    }
164	
165	    /**
166	     * @ch 停止進場盤面效果：還原 ZoomIn；await 還原動畫播畢才 resolve（盤面回正後才續流程）。
167	     * 另發 SHAKE STOP 作安全網（單次震動通常已自停，此處確保退場不殘留震動）。
168	     * RESTORE_ZOOM 若未曾 ZoomIn（m_isZoomed=false）會立即回調，不會 hang。
169	     */
170	    private StopBoardEffect(): Promise<void>
171	    {
172	        eventManager.Dispatch( SHAKE_EVENT.STOP );
173	        return new Promise<void>( resolve =>
174	        {
175	            eventManager.Dispatch(
176	                REEL_MANAGER_EVENT.RESTORE_ZOOM,
177	                FeatureWheelShowState.BOARD_ZOOM_OUT_DURATION,
178	                () => resolve()
179	            );
180	        } );
181	    }
182	
183	    /**
184	     * @ch 包一層 Promise 等進場 Active 播畢（PLAY_ENTER；Spine 缺失由 Manager 立即回調）
185	     */
186	    private PlayWheelEnter(): Promise<void>
187	    {
188	        return new Promise<void>( resolve =>
189	        {
190	            eventManager.Dispatch( FEATURE_WHEEL_EVENT.PLAY_ENTER, () => resolve() );
191	        } );
192	    }
193	
194	    /**
195	     * @ch 包一層 Promise 等退場 Out 播畢（PLAY_EXIT；Spine 缺失由 Manager 立即回調）
196	     */
197	    private PlayWheelExit(): Promise<void>
198	    {
199	        return new Promise<void>( resolve =>
200	        {
201	            eventManager.Dispatch( FEATURE_WHEEL_EVENT.PLAY_EXIT, () => resolve() );
202	        } );
203	    }
204	
205	    /**
206	     * @ch 包一層 Promise 等單次 PLAY_SPIN 完成回調
207	     * @param landIndex 落點格索引（已由呼叫端確認 0~11 範圍）
208	     */
209	    private PlaySpinOnce( landIndex: number ): Promise<SpinResult | null>
210	    {
211	        return new Promise<SpinResult | null>( resolve =>
212	        {
213	            eventManager.Dispatch(
214	                FEATURE_WHEEL_EVENT.PLAY_SPIN,
215	                landIndex,
216	                ( result: SpinResult ) => resolve( result ?? null )
217	            );
218	        } );
219	    }
220	
221	    public OnProcess()
222	    {
223	
224	    }
225	
226	    public OnLeave()
227	    {
228	
229	    }
230	
231	    /**
232	     * @ch 播放飛行效果
233	     * @param data 飛行效果資料
234	     */
235	    private async PlayFlyEffect( data: ar2es2Proto.IFeatureResult )
236	    {
237	        log( "PlayFlyEffect data: " + JSON.stringify( data ) );
238	
239	        // ⚠️ 暫代演出：尚無專屬「功能飛向盤面」Spine，先借用 Scatter→MagicPot 飛行動畫頂著。
240	        //    待正式資源就緒，改 dispatch 對應的功能飛行事件即可（起終點取法不變）。
241	        const positions = data.Positions ?? [];
242	        if ( positions.length === 0 )
243	        {
244	            return; // 無落點位置 → 無暫代飛行可播
245	        }
246	
247	        // 起點：向 FeatureWheelManager 取目標節點（同步 dispatch；callback 立即回傳節點）
248	        let startNode: Node = null;
249	        eventManager.Dispatch( FEATURE_WHEEL_EVENT.GET_TARGET_NODE, ( node: Node ) => { startNode = node; } );
250	        if ( startNode == null || !startNode.isValid )
251	        {
252	            console.warn( "[FeatureWheelShowState] PlayFlyEffect 取不到目標節點，跳過暫代飛行" );
253	            return;
254	        }
255	        const startWorldPos = startNode.getWorldPosition();
256	
257	        // 終點：每個 Position 對應的盤面符號世界座標；各位置平行飛、全部播畢才續流程。
258	        // 註：暫代借用的 PLAY_SHOW_SCATTER_TO_MAGIC_POT_ANIMATION 在「建立節點失敗」分支不回 callback，
259	        //    與 ScatterShowState 既有用法同源風險（無 timeout），暫代階段可接受。
260	        await Promise.all( positions.map( pos =>
261	        {
262	            const endWorldPos = this.m_gameView.SlotReels.GetSymbolInitWorldPositionFromPosition( pos );
263	            return new Promise<void>( resolve =>
264	            {
265	                eventManager.Dispatch( FLY_EVENT.PLAY_SHOW_SCATTER_TO_MAGIC_POT_ANIMATION, startWorldPos, endWorldPos, () => resolve() );
266	            } );
267	        } ) );
268	
269	        await Define.Wait( this.m_gameView, 0.2 );
270	    }
271	
272	    /**
273	     * @ch 播放標記效果
274	     * @param data 標記效果資料
275	     */
276	    private async PlayMarkEffect( data: ar2es2Proto.IFeatureResult )
277	    {
278	        log( "PlayMarkEffect data: " + JSON.stringify( data ) );
279	
280	        // 轉到 GRAND JP：不播標配標記，直接播 JP 報獎（JP_Manager 已實作，await 等報獎演完再續迴圈）。
281	        if ( data.Type === FeatureWheelSegmentType.GrandJP )
282	        {
283	            await new Promise<void>( resolve =>
284	            {
285	                eventManager.Dispatch( JP_EVENT.PLAY_SHOW_AWARD, JP_Type.GRAND, () => resolve() );
286	            } );
287	            return;
288	        }
289	
290	        await new Promise<void>( resolve =>
291	        {
292	            eventManager.Dispatch( FEATURE_MARK_EVENT.SHOW_MARK, data.Type, data.Positions ?? [], data.Multipliers ?? [], () => resolve() );
293	        } );
294	    }
295	
296	    /**
297	     * @ch 播放符號轉換效果
298	     * @param data 符號轉換效果資料
299	     */
300	    private async PlaySymbolTransferEffect( data: ar2es2Proto.ITransformInfo[] )
301	    {
302	        await new Promise<void>( resolve =>
303	        {
304	            eventManager.Dispatch( FEATURE_MARK_EVENT.APPLY_TRANSFER, data, () => resolve() );
305	        } );
306	    }
307	}
