185	        this.UnregisterTestKeyCodes();
186	    }
187	
188	    /**
189	     * @ch 每幀 Idle 緩轉：僅在 Idle 態且非轉動中執行（兩旋轉路徑互斥，不同幀寫 m_wheelNode）
190	     * 方向跟隨 m_clockwise（順時針 = z 遞減，與 ComputeTargetAngle 一致）
191	     */
192	    update(dt: number) {
193	        if (!this.m_isIdle || this.m_isSpinning) {
194	            return;
195	        }
196	        if (this.m_idleSecondsPerRev <= 0) {
197	            return;
198	        }
199	        if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
200	            return;
201	        }
202	        const dir = this.m_clockwise ? -1 : 1;
203	        const deltaAngle = dir * (360 / this.m_idleSecondsPerRev) * dt;
204	        // 正規化防 BC-8 連續累積漂移（與 RotateToIndex 收尾一致），spin 起點讀 currentAngle 仍正確
205	        const next = NormalizeAngle(this.m_wheelNode.eulerAngles.z + deltaAngle);
206	        this.m_wheelNode.setRotationFromEuler(0, 0, next);
207	    }
