210	    //#region 事件註冊
211	    private RegisterEvent() {
212	        if (this.m_isEventRegistered) {
213	            return;
214	        }
215	        this.m_isEventRegistered = true;
216	        this.EVENT_LIST.forEach(event => eventManager.Register(event, this));
217	    }
218	
219	    private UnregisterEvent() {
220	        if (!this.m_isEventRegistered) {
221	            return;
222	        }
223	        this.EVENT_LIST.forEach(event => eventManager.UnRegister(event, this));
224	        this.m_isEventRegistered = false;
225	    }
