227	    /**
228	     * @ch 事件分派
229	     */
230	    OnEvent(event: string, ...args: any[]) {
231	        switch (event) {
232	            case FEATURE_WHEEL_EVENT.INIT:
233	                if (args.length > 0 && typeof args[0] === 'object' && args[0] !== null) {
234	                    this.Init(args[0]);
235	                } else {
236	                    error('FeatureWheel INIT 參數無效');
237	                }
238	                break;
239	
240	            case FEATURE_WHEEL_EVENT.SET_WHEEL_DATA:
241	                if (args.length > 0 && Array.isArray(args[0])) {
242	                    this.SetWheelData(args[0]);
243	                } else {
244	                    error('FeatureWheel SET_WHEEL_DATA 參數無效');
245	                }
246	                break;
247	
248	            case FEATURE_WHEEL_EVENT.PLAY_SPIN:
249	                if (args.length > 0 && typeof args[0] === 'number') {
250	                    this.PlaySpin(args[0], typeof args[1] === 'function' ? args[1] : undefined);
251	                } else {
252	                    error('FeatureWheel PLAY_SPIN 參數無效');
253	                }
254	                break;
255	
256	            case FEATURE_WHEEL_EVENT.SHOW_UI:
257	                this.SetUIShow(true);
258	                break;
259	
260	            case FEATURE_WHEEL_EVENT.HIDE_UI:
261	                this.SetUIShow(false);
262	                break;
263	
264	            case FEATURE_WHEEL_EVENT.PLAY_ENTER:
265	                this.PlayEnter(typeof args[0] === 'function' ? args[0] : undefined);
266	                break;
267	
268	            case FEATURE_WHEEL_EVENT.PLAY_EXIT:
269	                this.PlayExit(typeof args[0] === 'function' ? args[0] : undefined);
270	                break;
271	
272	            case FEATURE_WHEEL_EVENT.RESUME_IDLE:
273	                this.ResumeIdle();
274	                break;
275	
276	            case FEATURE_WHEEL_EVENT.HIDE_RESULT:
277	                this.HideResult();
278	                break;
279	
280	            case FEATURE_WHEEL_EVENT.GET_TARGET_NODE:
281	                if (typeof args[0] === 'function') {
282	                    args[0](this.GetTargetNode());
283	                } else {
284	                    error('FeatureWheel GET_TARGET_NODE 缺少 callback');
285	                }
286	                break;
287	        }
288	    }
