290	    /**
291	     * @ch 取得目標節點（飛行演出起點）：m_targetNode → 根節點 → 自身節點 依序 fallback。
292	     * @returns 目標 Node（理論上不為 null；m_targetNode/m_rootNode 未掛時退回 this.node）
293	     */
294	    private GetTargetNode(): Node {
295	        return this.m_targetNode ?? this.m_rootNode ?? this.node;
296	    }
