299	    //#region 方法
300	    /**
301	     * @ch 初始化（IF-1）
302	     */
303	    private Init(gameView: GameView) {
304	        this.m_gameView = gameView;
305	        this.m_isInit = true;
306	    }
307	
308	    /**
309	     * @ch 設置 12 格資料並更新 icon（IF-2 / BC-5 / EH-2）
310	     * @param segments server 給的 12 格資料
311	     */
312	    private SetWheelData(segments: SegmentDescriptor[]) {
313	        // BC-9 行為約束：轉動中拒絕換資料，避免落點與顯示不一致
314	        if (this.m_isSpinning) {
315	            warn('FeatureWheel SetWheelData 轉動中，拒絕本次設置');
316	            return;
317	        }
318	        if (!segments) {
319	            warn('FeatureWheel SetWheelData 資料為空');
320	            return;
321	        }
322	
323	        // EH-2：長度 > 12 取前 12
324	        if (segments.length > FEATURE_WHEEL_SEGMENT_COUNT) {
325	            warn(`FeatureWheel SetWheelData 長度 ${segments.length} > ${FEATURE_WHEEL_SEGMENT_COUNT}，取前 ${FEATURE_WHEEL_SEGMENT_COUNT} 格`);
326	        }
327	        this.m_segments = segments.slice(0, FEATURE_WHEEL_SEGMENT_COUNT);
328	
329	        // EH-2：長度 < 12 → 渲染已提供格，其餘格保持預設
330	        if (this.m_segments.length < FEATURE_WHEEL_SEGMENT_COUNT) {
331	            warn(`FeatureWheel SetWheelData 長度 ${this.m_segments.length} < ${FEATURE_WHEEL_SEGMENT_COUNT}，其餘格保持預設`);
332	        }
333	
334	        this.BindSegmentIcons();
335	
336	        this.m_isIdle = true;
337	    }
338	
339	    /**
340	     * @ch 依當前資料綁定各格 icon（BC-4 / EH-2）
341	     * None / 無資料格 → 清空不顯示；其餘依 type 換圖。倍率值已移除，Label 一律清空防殘留。
342	     * FS_BG 底圖：僅該格 type 為 FreeGame 時開啟（作底凸顯免費遊戲符號）；其餘格關閉以保冪等（R-2）。
343	     */
344	    private BindSegmentIcons() {
345	        // 迭代固定 12 格確保冪等（R-2）：二次設定變少時，超出資料的格重置為預設，不殘留舊值
346	        for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
347	            const seg = i < this.m_segments.length ? this.m_segments[i] : null;
348	
349	            // 換 icon：None / 無資料格 → 清空（暫不顯示）；其餘依 type 換圖（BC-4）
350	            const spriteChange = this.m_segmentSpriteChanges[i];
351	            if (spriteChange) {
352	                if (!seg || seg.type === FeatureWheelSegmentType.None) {
353	                    spriteChange.ClearSprite();
354	                } else {
355	                    spriteChange.ChangeSpriteByIndex(TypeToIconIndex(seg.type));
356	                }
357	
358	                // FS_BG 底圖：與 icon 同生命週期，從同格 item root 取子節點（無資料/非 FreeGame 一律關，保冪等）
359	                const fsBg = spriteChange.node?.getChildByName('FS_BG');
360	                if (fsBg) {
361	                    fsBg.active = !!seg && seg.type === FeatureWheelSegmentType.FreeGame;
362	                }
363	            }
364	
365	            // 倍率值已移除：清空 Label，避免殘留設計期/前一次的文字
366	            const label = this.m_segmentValueLabels[i];
367	            if (label) {
368	                label.string = '';
369	            }
370	        }
371	    }
372	
373	    /**
374	     * @ch 轉動並落在指定格（IF-3 / BC-3 / BC-6 / BC-7 / BC-8 / BC-9 / EH-1 / EH-3）
375	     * 守衛順序（DR-10）：① 轉動中重入 → ② 未初始化/無資料 → ③ landIndex 範圍
376	     * 完成訊號鏈（DR-2 / BC-7）：await 轉動 → await 落點演出 → callback → 最後釋放 m_isSpinning
377	     * @param landIndex 落點格索引 (0~11)
378	     * @param callback 完成回調，帶選中格 {index, type, value}
379	     */
380	    private async PlaySpin(landIndex: number, callback?: (result: SpinResult) => void) {
381	        // ① BC-9 轉動中重入 → 忽略
382	        if (this.m_isSpinning) {
383	            warn('FeatureWheel PlaySpin 轉動中，忽略本次請求');
384	            return;
385	        }
386	        // ② EH-3 未初始化或無資料
387	        if (!this.m_isInit || this.m_segments.length === 0) {
388	            warn('FeatureWheel PlaySpin 未初始化或尚未設置輪盤資料');
389	            return;
390	        }
391	        // ③ EH-1 landIndex 範圍
392	        if (landIndex < 0 || landIndex >= FEATURE_WHEEL_SEGMENT_COUNT) {
393	            warn(`FeatureWheel PlaySpin landIndex ${landIndex} 超出範圍 0~${FEATURE_WHEEL_SEGMENT_COUNT - 1}`);
394	            return;
395	        }
396	
397	        this.m_isSpinning = true;
398	        // 轉動開始即關閉 Idle：轉完「不」自動恢復；待盤面其他表演結束由 RESUME_IDLE 手動恢復
399	        this.m_isIdle = false;
400	        try {
401	            await this.RotateToIndex(landIndex);     // BC-3 / BC-6
402	            await this.PlayLandAnnounce(landIndex);  // BC-7
403	            const seg = this.m_segments[landIndex];
404	            // callback 包獨立 try（R-1）：呼叫端 callback 自身例外不被遮蔽成「轉動失敗」
405	            try {
406	                callback?.({ index: landIndex, type: seg.type });
407	            } catch (cbErr) {
408	                error('FeatureWheel PlaySpin callback 執行失敗: ' + cbErr);
409	            }
410	        } catch (e) {
411	            error('FeatureWheel PlaySpin 轉動/演出失敗: ' + e);
412	        } finally {
413	            // BC-7：釋放點在 callback 之後，避免演出/回呼期間被重入
414	            this.m_isSpinning = false;
415	        }
416	    }
417	
418	    /**
419	     * @ch 旋轉到 landIndex，停在頂端指針（BC-3 / BC-6）
420	     * 角度計算用 ComputeTargetAngle（依 m_clockwise 單向單調，不沿用會反向的 angleDiff）
421	     */
422	    private RotateToIndex(landIndex: number): Promise<void> {
423	        return new Promise<void>((resolve) => {
424	            if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
425	                resolve();
426	                return;
427	            }
428	            const currentAngle = this.m_wheelNode.eulerAngles.z;
429	            const targetAngle = ComputeTargetAngle(landIndex, currentAngle, this.m_clockwise);
430	            const anim = { angle: currentAngle };
431	            tween(anim)
432	                .to(FeatureWheelManager.ROTATE_TIME, { angle: targetAngle }, {
433	                    easing: 'cubicOut',
434	                    onUpdate: () => {
435	                        if (this.m_wheelNode?.isValid) {
436	                            this.m_wheelNode.setRotationFromEuler(0, 0, anim.angle);
437	                        }
438	                    },
439	                })
440	                .call(() => {
441	                    // DR-9：轉動結束後正規化角度，防 BC-8 連續轉動累積漂移
442	                    if (this.m_wheelNode?.isValid) {
443	                        this.m_wheelNode.setRotationFromEuler(0, 0, NormalizeAngle(targetAngle));
444	                    }
445	                    resolve();
446	                })
447	                .start();
448	        });
449	    }
450	
451	    /**
452	     * @ch 落點演出（BC-7）：BigWheel Spine 取代結果展示牌——依落點 type 切 skin，播 Collect「中間功能亮起」，await 播畢才 resolve。
453	     * 時序：呼叫端在 RotateToIndex（轉輪停下）後呼叫，符合「轉輪停下來後中間功能亮起」。
454	     * Collect 播畢後中間維持亮起（end pose），退場由 PlayExit 的 Out（盤面回歸+暗掉）負責。
455	     * Spine 缺失（m_bigWheelSpine 未綁）→ PlaySpineOnce 立即 resolve，不 hang 呼叫端。
456	     */
457	    private async PlayLandAnnounce(landIndex: number): Promise<void> {
458	        const seg = this.m_segments[landIndex];
459	        if (!seg) {
460	            return;
461	        }
462	        // 先切到落點功能 skin（Multiplier/Upgrade/Shift 直對；FG/Grand/None → default），再播 Collect
463	        this.SetSpineSkin(TypeToSkin(seg.type));
464	        await this.PlaySpineOnce(BIG_WHEEL_ANIM.Collect);
465	    }
466	
467	    /**
468	     * @ch [已停用] 套用落點 type 對應圖到結果展示牌 SpriteChange。
469	     * ⚠️ Collect 動畫取代結果展示牌後無呼叫者；保留待美術定案後連同 m_result* 屬性整條移除。
470	     */
471	    private ApplyResultSprite(spriteChange: SpriteChange | null, type: FeatureWheelSegmentType) {
472	        if (!spriteChange) {
473	            return;
474	        }
475	        if (type === FeatureWheelSegmentType.None) {
476	            spriteChange.ClearSprite();
477	        } else {
478	            spriteChange.ChangeSpriteByIndex(TypeToIconIndex(type));
479	        }
480	    }
481	
482	    /**
483	     * @ch [已停用] 結果展示牌收場（HIDE_RESULT / SetUIShow(false) 呼叫）。
484	     * ⚠️ 不可在此關閉 m_resultNode——該節點現為 BigWheel Spine 的父容器，關閉會連帶隱藏 BigWheel。
485	     * Collect 取代結果展示牌後無實際收場需求，保留空實作以相容既有事件/呼叫；
486	     * TODO(清理)：result-card 路徑（ApplyResultSprite / m_result* 屬性）全面移除後刪此方法。
487	     */
488	    private HideResult() {
489	        // no-op：m_resultNode 已挪作 BigWheel 容器，不可在此 active=false
490	    }
491	
492	    /**
493	     * @ch 顯示/隱藏 UI（IF-4）
494	     */
495	    private SetUIShow(isShow: boolean) {
496	        if (this.m_rootNode) {
497	            this.m_rootNode.active = isShow;
498	        }
499	        // 隱藏 UI 時一併收掉結果展示牌，避免下次顯示殘留上一輪落點符號
500	        if (!isShow) {
501	            this.HideResult();
502	        }
503	        // Idle：顯示時開始緩轉、隱藏時停止（PlaySpin 後不自動恢復，須由 RESUME_IDLE 手動恢復）
504	        this.m_isIdle = isShow;
505	    }
506	
507	    /**
508	     * @ch 手動恢復 Idle 緩轉（IF）+ 播 BigWheel Idle 待機呼吸
509	     * 用途：PlaySpin 後輪盤停住，呼叫端在盤面其他表演結束後觸發此方法才續轉
510	     * 注意：若仍在轉動中，由 update 的 m_isSpinning 守衛延後至轉完才實際緩轉
511	     * Spine：回 default skin + 播 Idle 循環（呼吸效果）；軟體 12 格緩轉與 Spine 呼吸為兩獨立層
512	     */
513	    private ResumeIdle() {
514	        this.m_isIdle = true;
515	        this.SetSpineSkin(BIG_WHEEL_DEFAULT_SKIN);
516	        this.PlaySpineLoop(BIG_WHEEL_ANIM.Idle);
517	    }
