519	    /**
520	     * @ch 播放進場 Active（一個 round 一次，落在第一次轉動前）；播畢回調。
521	     * 進場用 default skin（中間尚未落定功能）。Spine 缺失 → PlaySpineOnce 立即 resolve，不 hang 呼叫端。
522	     * @param onDone 動畫播畢回調
523	     */
524	    private async PlayEnter(onDone?: () => void) {
525	        this.SetSpineSkin(BIG_WHEEL_DEFAULT_SKIN);
526	        await this.PlaySpineOnce(BIG_WHEEL_ANIM.Active);
527	        try {
528	            onDone?.();
529	        } catch (e) {
530	            error('FeatureWheel PlayEnter onDone 失敗: ' + e);
531	        }
532	    }
