534	    /**
535	     * @ch 播放退場 Out（一個 round 一次，落在全部轉動與效果演完後）；播畢回調。
536	     * Out 的「中間功能暗掉」作用於當前落點 skin，故 setSkin(default) 放在 Out 之後（暗掉後再回 default 待 Idle）。
537	     * @param onDone 動畫播畢回調
538	     */
539	    private async PlayExit(onDone?: () => void) {
540	        await this.PlaySpineOnce(BIG_WHEEL_ANIM.Out);
541	        this.SetSpineSkin(BIG_WHEEL_DEFAULT_SKIN);
542	        try {
543	            onDone?.();
544	        } catch (e) {
545	            error('FeatureWheel PlayExit onDone 失敗: ' + e);
546	        }
547	    }
