549	    /**
550	     * @ch 設定 BigWheel skin（null/失效守衛）。委派 BaseSpine.SetSkin（內含 setSlotsToSetupPose）
551	     * @param skinName skin 名（default/Multiplier/Shift/Upgrade）
552	     */
553	    private SetSpineSkin(skinName: string) {
554	        if (this.m_bigWheelSpine && this.m_bigWheelSpine.isValid) {
555	            this.m_bigWheelSpine.SetSkin(skinName);
556	        }
557	    }
558	
559	    /**
560	     * @ch 播放 BigWheel 單次（非循環）動畫，await 播畢/中斷才 resolve。委派 SpineKit（經 BaseSpine.PlayAnimation）。
561	     * Spine 缺失 → 立即 resolve；動畫名無效 → BaseSpine 內部 warn + 回 false，皆不 hang 呼叫端（DR-2 完成訊號鏈防 hang）。
562	     * @param animName 動畫名（Active/Collect/Out）
563	     */
564	    private async PlaySpineOnce(animName: string): Promise<void> {
565	        if (!this.m_bigWheelSpine || !this.m_bigWheelSpine.isValid) {
566	            return;
567	        }
568	        // BaseSpine.PlayAnimation 回 Promise<boolean>（播畢/中斷時 resolve）；此處只需等其結束，忽略結果旗標
569	        await this.m_bigWheelSpine.PlayAnimation(animName, undefined, false);
570	    }
571	
572	    /**
573	     * @ch 播放 BigWheel 循環動畫（Idle 待機呼吸），不 await（循環動畫不等完成）。委派 SpineKit（經 BaseSpine.PlayAnimation）。
574	     * @param animName 動畫名（Idle）
575	     */
576	    private PlaySpineLoop(animName: string) {
577	        if (!this.m_bigWheelSpine || !this.m_bigWheelSpine.isValid) {
578	            return;
579	        }
580	        // 循環播放：isLoop=true；回傳 Promise 於首圈完成 resolve，不 await（不影響續循環）
581	        this.m_bigWheelSpine.PlayAnimation(animName, undefined, true);
582	    }
