606	    /**
607	     * @ch 註冊測試按鍵（僅 DEBUG 構建生效；正式構建零副作用）
608	     */
609	    private RegisterTestKeyCodes() {
610	        if (!DEBUG) {
611	            return;
612	        }
613	        input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
