626	    /**
627	     * @ch 檢查測試按鍵，走真實 eventManager 事件路徑驗證 FeatureWheel 功能
628	     * DIGIT_1：初始化 + 設定預設輪盤資料 + 顯示 UI（一鍵就緒）
629	     * DIGIT_2：轉動到下一格（循環 0~11）並印出落點結果（驗證旋轉/落點演出/callback）
630	     * DIGIT_3：重設隨機輪盤資料（驗證 icon 與乘倍數值動態更新）
631	     * DIGIT_4：切換顯示/隱藏 UI
632	     */
633	    private CheckTestKeyCode(event: EventKeyboard) {
634	        switch (event.keyCode) {
635	            // case KeyCode.DIGIT_1:
636	            //     log('[FeatureWheel 測試] 初始化 + 設定預設資料 + 顯示 UI');
637	            //     // INIT 僅需非 null 物件以通過參數驗證並翻起 m_isInit；
638	            //     // m_gameView 在本元件未被讀取，測試以 this.node 佔位即可
639	            //     eventManager.Dispatch(FEATURE_WHEEL_EVENT.INIT, this.node);
640	            //     eventManager.Dispatch(FEATURE_WHEEL_EVENT.SET_WHEEL_DATA, GetDefaultSegments());
641	            //     eventManager.Dispatch(FEATURE_WHEEL_EVENT.SHOW_UI);
642	            //     break;
643	
644	            case KeyCode.DIGIT_2: {
645	                const landIndex = this.m_testLandIndex % FEATURE_WHEEL_SEGMENT_COUNT;
646	                this.m_testLandIndex++;
647	                log(`[FeatureWheel 測試] 轉動到第 ${landIndex} 格`);
648	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.PLAY_SPIN, landIndex, (result: SpinResult) => {
649	                    log(`[FeatureWheel 測試] 落點結果 index=${result.index} type=${result.type}`);
650	                });
651	                break;
652	            }
653	            
654	            case KeyCode.DIGIT_3:
655	                log('[FeatureWheel 測試] 恢復 Idle 緩轉');
656	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.HIDE_RESULT);
657	                eventManager.Dispatch( FEATURE_WHEEL_EVENT.RESUME_IDLE );
658	                break;
659	
660	            case KeyCode.DIGIT_4:
661	                this.m_testUIShown = !this.m_testUIShown;
662	                log(`[FeatureWheel 測試] 切換 UI 顯示 → ${this.m_testUIShown}`);
663	                eventManager.Dispatch(this.m_testUIShown ? FEATURE_WHEEL_EVENT.SHOW_UI : FEATURE_WHEEL_EVENT.HIDE_UI);
664	                break;
665	        }
666	    }
667	
668	    /**
669	     * @ch 產生 12 格隨機測試資料（type 隨機）
670	     */
671	    private BuildRandomTestSegments(): SegmentDescriptor[] {
672	        const types = [
673	            FeatureWheelSegmentType.SymbolConvert,
674	            FeatureWheelSegmentType.Multiplier,
675	            FeatureWheelSegmentType.Upgrade,
676	            FeatureWheelSegmentType.GrandJP,
677	            FeatureWheelSegmentType.FreeGame,
678	        ];
679	        const segments: SegmentDescriptor[] = [];
680	        for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
681	            const type = types[Math.floor(Math.random() * types.length)];
682	            segments.push({ type });
683	        }
684	        return segments;
685	    }
686	    //#endregion 測試功能
687	}
