import { _decorator, Component, Node, Label, tween, warn, error, EventKeyboard, Input, input, KeyCode, log } from 'cc';
import { DEV, DEBUG } from 'cc/env';
import GameView from '../GameView';
import { eventManager } from 'db://astarte-framework/Managers';
import { SpriteChange } from '../Common/SpriteChange';
import { BaseSpine } from '../Spine/BaseSpine';
import {
    SegmentDescriptor,
    SpinResult,
    FeatureWheelSegmentType,
    FEATURE_WHEEL_SEGMENT_COUNT,
    TypeToIconIndex,
    TypeToSkin,
    BIG_WHEEL_DEFAULT_SKIN,
    ComputeTargetAngle,
    NormalizeAngle,
    GetDefaultSegments,
} from './FeatureWheelTypes';

const { ccclass, property } = _decorator;

/**
 * @ch BigWheel Spine 動畫名（對齊 EyeStrike2_BigWheel animations）
 * Active=進場(盤面下降+灰塵+光效) / Collect=落點中間功能亮起 / Out=退場(盤面回歸+功能暗掉) / Idle=待機呼吸
 */
const BIG_WHEEL_ANIM = {
    Active: 'Active',
    Collect: 'Collect',
    Out: 'Out',
    Idle: 'Idle',
} as const;

/**
 * @ch Feature Wheel 事件（獨立命名空間，與舊 MULTIPLIER_EVENT 不衝突，支援共存）
 */
export const FEATURE_WHEEL_EVENT = {
    /**
     * @ch 初始化
     * @param gameView 遊戲視窗
     */
    INIT: 'FEATURE_WHEEL_INIT',

    /**
     * @ch 設置 12 格輪盤資料（server 給）
     * @param segments SegmentDescriptor[]（每格 type；None 格不顯示）
     */
    SET_WHEEL_DATA: 'FEATURE_WHEEL_SET_WHEEL_DATA',

    /**
     * @ch 轉動並落在指定格
     * @param landIndex 落點格索引 (0~11)
     * @param callback (選填) (result: SpinResult) => void
     */
    PLAY_SPIN: 'FEATURE_WHEEL_PLAY_SPIN',

    /**@ch 顯示 UI*/
    SHOW_UI: 'FEATURE_WHEEL_SHOW_UI',

    /**@ch 隱藏 UI*/
    HIDE_UI: 'FEATURE_WHEEL_HIDE_UI',

    /**
     * @ch 播放進場 Active（盤面下降+灰塵+光效；一個 round 僅一次，落在第一次轉動前）
     * @param callback (選填) () => void，動畫播畢回調（Spine 缺失立即回調，不 hang）
     */
    PLAY_ENTER: 'FEATURE_WHEEL_PLAY_ENTER',

    /**
     * @ch 播放退場 Out（盤面回歸+中間功能暗掉；一個 round 僅一次，落在全部轉動與效果演完後）
     * @param callback (選填) () => void，動畫播畢回調（Spine 缺失立即回調，不 hang）
     */
    PLAY_EXIT: 'FEATURE_WHEEL_PLAY_EXIT',

    /**
     * @ch 手動恢復 Idle 緩轉
     * PlaySpin 後輪盤停住不自動恢復；待盤面其他表演結束，由呼叫端 dispatch 此事件才繼續緩轉
     */
    RESUME_IDLE: 'FEATURE_WHEEL_RESUME_IDLE',

    /**
     * @ch 隱藏結果展示牌（暫代落點演出的退場）
     * PlayLandAnnounce 秀出展示牌後即 resolve、不自動收；由呼叫端在結果演出結束後 dispatch 此事件退場
     */
    HIDE_RESULT: 'FEATURE_WHEEL_HIDE_RESULT',

    /**
     * @ch 獲取目標節點
     * @param callback targetNode: Node 回傳目標節點
     */
    GET_TARGET_NODE: 'FEATURE_WHEEL_GET_TARGET_NODE',
};

/**
 * @ch Feature Wheel 輪盤 UI 元件
 * 單一職責：顯示 12 格、平時 Idle 緩轉、依 server 資料換 icon、轉動落在指定格、播落點演出、把選中功能拋給外部
 * 不碰盤面標記/重轉/改符號（呼叫端責任）
 */
@ccclass('FeatureWheelManager')
export class FeatureWheelManager extends Component {
    //#region 屬性
    /**@ch 根節點（顯示/隱藏）*/
    @property({ type: Node, displayName: '根節點' })
    private m_rootNode: Node = null;

    /**@ch 輪盤旋轉節點（轉動的是這個，頂端指針固定不動）*/
    @property({ type: Node, displayName: '輪盤旋轉節點' })
    private m_wheelNode: Node = null;

    /**@ch 12 格 icon 的 SpriteChange（順序對應格 0~11）*/
    @property({ type: [SpriteChange], displayName: '12 格 icon SpriteChange' })
    private m_segmentSpriteChanges: SpriteChange[] = [];

    /**@ch 12 格乘倍數值 Label（非乘倍格留空字串；順序對應格 0~11）*/
    @property({ type: [Label], displayName: '12 格乘倍數值 Label' })
    private m_segmentValueLabels: Label[] = [];

    /**@ch 12 格落點演出節點（順序對應格 0~11；現僅供 DevAssertConfig 數量檢查，落點演出已改用結果展示牌）*/
    @property({ type: [Node], displayName: '12 格落點演出節點' })
    private m_segmentNodes: Node[] = [];

    /**@ch 飛行演出起點根節點 */
    @property({ type: Node, displayName: '飛行演出起點根節點' })
    private m_targetNode: Node = null;

    /**
     * @ch BigWheel（EyeStrike2_BigWheel）BaseSpine：進場 Active / 落點 Collect / 退場 Out / 待機 Idle，skin 依落點功能切換。
     * 播放走 BaseSpine（內部 SpineKit，含動畫存在檢查 + setSlotsToSetupPose）。拖 FeatureWheelResult 節點（其上有 BaseSpine）。
     * Collect 取代結果展示牌（m_result* 已停用，僅保留屬性避免 prefab 反序列化警告）。
     */
    @property({ type: BaseSpine, displayName: 'BigWheel BaseSpine' })
    private m_bigWheelSpine: BaseSpine = null;

    /**@ch 轉動方向：勾選=順時針，取消=逆時針（預設順時針）*/
    @property({ displayName: '順時針轉動' })
    private m_clockwise: boolean = true;

    /**@ch Idle 緩轉一圈秒數（越大越慢；≤0 視為不緩轉）；方向跟隨「順時針轉動」*/
    @property({ displayName: 'Idle 一圈秒數' })
    private m_idleSecondsPerRev: number = 60;
    //#endregion 屬性

    //#region 常數
    /**@ch 轉動時間（秒）；拉長以降低峰值角速度，減輕 12 格重複圖樣的車輪錯覺（視覺反向）*/
    private static readonly ROTATE_TIME = 3;//2.5;
    //#endregion 常數

    //#region 變數
    /**@ch 遊戲視窗*/
    private m_gameView: GameView = null;
    /**@ch 是否初始化*/
    private m_isInit = false;
    /**@ch 是否轉動中（轉動中/閒置兩互斥態）*/
    private m_isSpinning = false;
    /**@ch 是否處於 Idle 緩轉態（SHOW_UI/RESUME_IDLE 開、HIDE_UI/PlaySpin 關；轉動中由 m_isSpinning 暫停，轉完不自動恢復）*/
    private m_isIdle = false;
    /**@ch 是否已註冊事件*/
    private m_isEventRegistered = false;
    /**@ch 當前 12 格資料*/
    private m_segments: SegmentDescriptor[] = [];

    /**@ch 事件列表*/
    private readonly EVENT_LIST: string[] = [
        FEATURE_WHEEL_EVENT.INIT,
        FEATURE_WHEEL_EVENT.SET_WHEEL_DATA,
        FEATURE_WHEEL_EVENT.PLAY_SPIN,
        FEATURE_WHEEL_EVENT.SHOW_UI,
        FEATURE_WHEEL_EVENT.HIDE_UI,
        FEATURE_WHEEL_EVENT.PLAY_ENTER,
        FEATURE_WHEEL_EVENT.PLAY_EXIT,
        FEATURE_WHEEL_EVENT.RESUME_IDLE,
        FEATURE_WHEEL_EVENT.HIDE_RESULT,
        FEATURE_WHEEL_EVENT.GET_TARGET_NODE,
    ];
    //#endregion 變數

    //#region 生命週期
    onLoad() {
        this.RegisterEvent();
        this.DevAssertConfig();
        this.RegisterTestKeyCodes();
    }

    onDestroy() {
        this.UnregisterEvent();
        this.UnregisterTestKeyCodes();
    }

    /**
     * @ch 每幀 Idle 緩轉：僅在 Idle 態且非轉動中執行（兩旋轉路徑互斥，不同幀寫 m_wheelNode）
     * 方向跟隨 m_clockwise（順時針 = z 遞減，與 ComputeTargetAngle 一致）
     */
    update(dt: number) {
        if (!this.m_isIdle || this.m_isSpinning) {
            return;
        }
        if (this.m_idleSecondsPerRev <= 0) {
            return;
        }
        if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
            return;
        }
        const dir = this.m_clockwise ? -1 : 1;
        const deltaAngle = dir * (360 / this.m_idleSecondsPerRev) * dt;
        // 正規化防 BC-8 連續累積漂移（與 RotateToIndex 收尾一致），spin 起點讀 currentAngle 仍正確
        const next = NormalizeAngle(this.m_wheelNode.eulerAngles.z + deltaAngle);
        this.m_wheelNode.setRotationFromEuler(0, 0, next);
    }
    //#endregion 生命週期

    //#region 事件註冊
    private RegisterEvent() {
        if (this.m_isEventRegistered) {
            return;
        }
        this.m_isEventRegistered = true;
        this.EVENT_LIST.forEach(event => eventManager.Register(event, this));
    }

    private UnregisterEvent() {
        if (!this.m_isEventRegistered) {
            return;
        }
        this.EVENT_LIST.forEach(event => eventManager.UnRegister(event, this));
        this.m_isEventRegistered = false;
    }

    /**
     * @ch 事件分派
     */
    OnEvent(event: string, ...args: any[]) {
        switch (event) {
            case FEATURE_WHEEL_EVENT.INIT:
                if (args.length > 0 && typeof args[0] === 'object' && args[0] !== null) {
                    this.Init(args[0]);
                } else {
                    error('FeatureWheel INIT 參數無效');
                }
                break;

            case FEATURE_WHEEL_EVENT.SET_WHEEL_DATA:
                if (args.length > 0 && Array.isArray(args[0])) {
                    this.SetWheelData(args[0]);
                } else {
                    error('FeatureWheel SET_WHEEL_DATA 參數無效');
                }
                break;

            case FEATURE_WHEEL_EVENT.PLAY_SPIN:
                if (args.length > 0 && typeof args[0] === 'number') {
                    this.PlaySpin(args[0], typeof args[1] === 'function' ? args[1] : undefined);
                } else {
                    error('FeatureWheel PLAY_SPIN 參數無效');
                }
                break;

            case FEATURE_WHEEL_EVENT.SHOW_UI:
                this.SetUIShow(true);
                break;

            case FEATURE_WHEEL_EVENT.HIDE_UI:
                this.SetUIShow(false);
                break;

            case FEATURE_WHEEL_EVENT.PLAY_ENTER:
                this.PlayEnter(typeof args[0] === 'function' ? args[0] : undefined);
                break;

            case FEATURE_WHEEL_EVENT.PLAY_EXIT:
                this.PlayExit(typeof args[0] === 'function' ? args[0] : undefined);
                break;

            case FEATURE_WHEEL_EVENT.RESUME_IDLE:
                this.ResumeIdle();
                break;

            case FEATURE_WHEEL_EVENT.HIDE_RESULT:
                this.HideResult();
                break;

            case FEATURE_WHEEL_EVENT.GET_TARGET_NODE:
                if (typeof args[0] === 'function') {
                    args[0](this.GetTargetNode());
                } else {
                    error('FeatureWheel GET_TARGET_NODE 缺少 callback');
                }
                break;
        }
    }

    /**
     * @ch 取得目標節點（飛行演出起點）：m_targetNode → 根節點 → 自身節點 依序 fallback。
     * @returns 目標 Node（理論上不為 null；m_targetNode/m_rootNode 未掛時退回 this.node）
     */
    private GetTargetNode(): Node {
        return this.m_targetNode ?? this.m_rootNode ?? this.node;
    }
    //#endregion 事件註冊

    //#region 方法
    /**
     * @ch 初始化（IF-1）
     */
    private Init(gameView: GameView) {
        this.m_gameView = gameView;
        this.m_isInit = true;
    }

    /**
     * @ch 設置 12 格資料並更新 icon（IF-2 / BC-5 / EH-2）
     * @param segments server 給的 12 格資料
     */
    private SetWheelData(segments: SegmentDescriptor[]) {
        // BC-9 行為約束：轉動中拒絕換資料，避免落點與顯示不一致
        if (this.m_isSpinning) {
            warn('FeatureWheel SetWheelData 轉動中，拒絕本次設置');
            return;
        }
        if (!segments) {
            warn('FeatureWheel SetWheelData 資料為空');
            return;
        }

        // EH-2：長度 > 12 取前 12
        if (segments.length > FEATURE_WHEEL_SEGMENT_COUNT) {
            warn(`FeatureWheel SetWheelData 長度 ${segments.length} > ${FEATURE_WHEEL_SEGMENT_COUNT}，取前 ${FEATURE_WHEEL_SEGMENT_COUNT} 格`);
        }
        this.m_segments = segments.slice(0, FEATURE_WHEEL_SEGMENT_COUNT);

        // EH-2：長度 < 12 → 渲染已提供格，其餘格保持預設
        if (this.m_segments.length < FEATURE_WHEEL_SEGMENT_COUNT) {
            warn(`FeatureWheel SetWheelData 長度 ${this.m_segments.length} < ${FEATURE_WHEEL_SEGMENT_COUNT}，其餘格保持預設`);
        }

        this.BindSegmentIcons();

        this.m_isIdle = true;
    }

    /**
     * @ch 依當前資料綁定各格 icon（BC-4 / EH-2）
     * None / 無資料格 → 清空不顯示；其餘依 type 換圖。倍率值已移除，Label 一律清空防殘留。
     * FS_BG 底圖：僅該格 type 為 FreeGame 時開啟（作底凸顯免費遊戲符號）；其餘格關閉以保冪等（R-2）。
     */
    private BindSegmentIcons() {
        // 迭代固定 12 格確保冪等（R-2）：二次設定變少時，超出資料的格重置為預設，不殘留舊值
        for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
            const seg = i < this.m_segments.length ? this.m_segments[i] : null;

            // 換 icon：None / 無資料格 → 清空（暫不顯示）；其餘依 type 換圖（BC-4）
            const spriteChange = this.m_segmentSpriteChanges[i];
            if (spriteChange) {
                if (!seg || seg.type === FeatureWheelSegmentType.None) {
                    spriteChange.ClearSprite();
                } else {
                    spriteChange.ChangeSpriteByIndex(TypeToIconIndex(seg.type));
                }

                // FS_BG 底圖：與 icon 同生命週期，從同格 item root 取子節點（無資料/非 FreeGame 一律關，保冪等）
                const fsBg = spriteChange.node?.getChildByName('FS_BG');
                if (fsBg) {
                    fsBg.active = !!seg && seg.type === FeatureWheelSegmentType.FreeGame;
                }
            }

            // 倍率值已移除：清空 Label，避免殘留設計期/前一次的文字
            const label = this.m_segmentValueLabels[i];
            if (label) {
                label.string = '';
            }
        }
    }

    /**
     * @ch 轉動並落在指定格（IF-3 / BC-3 / BC-6 / BC-7 / BC-8 / BC-9 / EH-1 / EH-3）
     * 守衛順序（DR-10）：① 轉動中重入 → ② 未初始化/無資料 → ③ landIndex 範圍
     * 完成訊號鏈（DR-2 / BC-7）：await 轉動 → await 落點演出 → callback → 最後釋放 m_isSpinning
     * @param landIndex 落點格索引 (0~11)
     * @param callback 完成回調，帶選中格 {index, type, value}
     */
    private async PlaySpin(landIndex: number, callback?: (result: SpinResult) => void) {
        // ① BC-9 轉動中重入 → 忽略
        if (this.m_isSpinning) {
            warn('FeatureWheel PlaySpin 轉動中，忽略本次請求');
            return;
        }
        // ② EH-3 未初始化或無資料
        if (!this.m_isInit || this.m_segments.length === 0) {
            warn('FeatureWheel PlaySpin 未初始化或尚未設置輪盤資料');
            return;
        }
        // ③ EH-1 landIndex 範圍
        if (landIndex < 0 || landIndex >= FEATURE_WHEEL_SEGMENT_COUNT) {
            warn(`FeatureWheel PlaySpin landIndex ${landIndex} 超出範圍 0~${FEATURE_WHEEL_SEGMENT_COUNT - 1}`);
            return;
        }

        this.m_isSpinning = true;
        // 轉動開始即關閉 Idle：轉完「不」自動恢復；待盤面其他表演結束由 RESUME_IDLE 手動恢復
        this.m_isIdle = false;
        try {
            await this.RotateToIndex(landIndex);     // BC-3 / BC-6
            await this.PlayLandAnnounce(landIndex);  // BC-7
            const seg = this.m_segments[landIndex];
            // callback 包獨立 try（R-1）：呼叫端 callback 自身例外不被遮蔽成「轉動失敗」
            try {
                callback?.({ index: landIndex, type: seg.type });
            } catch (cbErr) {
                error('FeatureWheel PlaySpin callback 執行失敗: ' + cbErr);
            }
        } catch (e) {
            error('FeatureWheel PlaySpin 轉動/演出失敗: ' + e);
        } finally {
            // BC-7：釋放點在 callback 之後，避免演出/回呼期間被重入
            this.m_isSpinning = false;
        }
    }

    /**
     * @ch 旋轉到 landIndex，停在頂端指針（BC-3 / BC-6）
     * 角度計算用 ComputeTargetAngle（依 m_clockwise 單向單調，不沿用會反向的 angleDiff）
     */
    private RotateToIndex(landIndex: number): Promise<void> {
        return new Promise<void>((resolve) => {
            if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
                resolve();
                return;
            }
            const currentAngle = this.m_wheelNode.eulerAngles.z;
            const targetAngle = ComputeTargetAngle(landIndex, currentAngle, this.m_clockwise);
            const anim = { angle: currentAngle };
            tween(anim)
                .to(FeatureWheelManager.ROTATE_TIME, { angle: targetAngle }, {
                    easing: 'cubicOut',
                    onUpdate: () => {
                        if (this.m_wheelNode?.isValid) {
                            this.m_wheelNode.setRotationFromEuler(0, 0, anim.angle);
                        }
                    },
                })
                .call(() => {
                    // DR-9：轉動結束後正規化角度，防 BC-8 連續轉動累積漂移
                    if (this.m_wheelNode?.isValid) {
                        this.m_wheelNode.setRotationFromEuler(0, 0, NormalizeAngle(targetAngle));
                    }
                    resolve();
                })
                .start();
        });
    }

    /**
     * @ch 落點演出（BC-7）：BigWheel Spine 取代結果展示牌——依落點 type 切 skin，播 Collect「中間功能亮起」，await 播畢才 resolve。
     * 時序：呼叫端在 RotateToIndex（轉輪停下）後呼叫，符合「轉輪停下來後中間功能亮起」。
     * Collect 播畢後中間維持亮起（end pose），退場由 PlayExit 的 Out（盤面回歸+暗掉）負責。
     * Spine 缺失（m_bigWheelSpine 未綁）→ PlaySpineOnce 立即 resolve，不 hang 呼叫端。
     */
    private async PlayLandAnnounce(landIndex: number): Promise<void> {
        const seg = this.m_segments[landIndex];
        if (!seg) {
            return;
        }
        // 先切到落點功能 skin（Multiplier/Upgrade/Shift 直對；FG/Grand/None → default），再播 Collect
        this.SetSpineSkin(TypeToSkin(seg.type));
        await this.PlaySpineOnce(BIG_WHEEL_ANIM.Collect);
    }

    /**
     * @ch [已停用] 套用落點 type 對應圖到結果展示牌 SpriteChange。
     * ⚠️ Collect 動畫取代結果展示牌後無呼叫者；保留待美術定案後連同 m_result* 屬性整條移除。
     */
    private ApplyResultSprite(spriteChange: SpriteChange | null, type: FeatureWheelSegmentType) {
        if (!spriteChange) {
            return;
        }
        if (type === FeatureWheelSegmentType.None) {
            spriteChange.ClearSprite();
        } else {
            spriteChange.ChangeSpriteByIndex(TypeToIconIndex(type));
        }
    }

    /**
     * @ch [已停用] 結果展示牌收場（HIDE_RESULT / SetUIShow(false) 呼叫）。
     * ⚠️ 不可在此關閉 m_resultNode——該節點現為 BigWheel Spine 的父容器，關閉會連帶隱藏 BigWheel。
     * Collect 取代結果展示牌後無實際收場需求，保留空實作以相容既有事件/呼叫；
     * TODO(清理)：result-card 路徑（ApplyResultSprite / m_result* 屬性）全面移除後刪此方法。
     */
    private HideResult() {
        // no-op：m_resultNode 已挪作 BigWheel 容器，不可在此 active=false
    }

    /**
     * @ch 顯示/隱藏 UI（IF-4）
     */
    private SetUIShow(isShow: boolean) {
        if (this.m_rootNode) {
            this.m_rootNode.active = isShow;
        }
        // 隱藏 UI 時一併收掉結果展示牌，避免下次顯示殘留上一輪落點符號
        if (!isShow) {
            this.HideResult();
        }
        // Idle：顯示時開始緩轉、隱藏時停止（PlaySpin 後不自動恢復，須由 RESUME_IDLE 手動恢復）
        this.m_isIdle = isShow;
    }

    /**
     * @ch 手動恢復 Idle 緩轉（IF）+ 播 BigWheel Idle 待機呼吸
     * 用途：PlaySpin 後輪盤停住，呼叫端在盤面其他表演結束後觸發此方法才續轉
     * 注意：若仍在轉動中，由 update 的 m_isSpinning 守衛延後至轉完才實際緩轉
     * Spine：回 default skin + 播 Idle 循環（呼吸效果）；軟體 12 格緩轉與 Spine 呼吸為兩獨立層
     */
    private ResumeIdle() {
        this.m_isIdle = true;
        this.SetSpineSkin(BIG_WHEEL_DEFAULT_SKIN);
        this.PlaySpineLoop(BIG_WHEEL_ANIM.Idle);
    }

    /**
     * @ch 播放進場 Active（一個 round 一次，落在第一次轉動前）；播畢回調。
     * 進場用 default skin（中間尚未落定功能）。Spine 缺失 → PlaySpineOnce 立即 resolve，不 hang 呼叫端。
     * @param onDone 動畫播畢回調
     */
    private async PlayEnter(onDone?: () => void) {
        this.SetSpineSkin(BIG_WHEEL_DEFAULT_SKIN);
        await this.PlaySpineOnce(BIG_WHEEL_ANIM.Active);
        try {
            onDone?.();
        } catch (e) {
            error('FeatureWheel PlayEnter onDone 失敗: ' + e);
        }
    }

    /**
     * @ch 播放退場 Out（一個 round 一次，落在全部轉動與效果演完後）；播畢回調。
     * Out 的「中間功能暗掉」作用於當前落點 skin，故 setSkin(default) 放在 Out 之後（暗掉後再回 default 待 Idle）。
     * @param onDone 動畫播畢回調
     */
    private async PlayExit(onDone?: () => void) {
        await this.PlaySpineOnce(BIG_WHEEL_ANIM.Out);
        this.SetSpineSkin(BIG_WHEEL_DEFAULT_SKIN);
        try {
            onDone?.();
        } catch (e) {
            error('FeatureWheel PlayExit onDone 失敗: ' + e);
        }
    }

    /**
     * @ch 設定 BigWheel skin（null/失效守衛）。委派 BaseSpine.SetSkin（內含 setSlotsToSetupPose）
     * @param skinName skin 名（default/Multiplier/Shift/Upgrade）
     */
    private SetSpineSkin(skinName: string) {
        if (this.m_bigWheelSpine && this.m_bigWheelSpine.isValid) {
            this.m_bigWheelSpine.SetSkin(skinName);
        }
    }

    /**
     * @ch 播放 BigWheel 單次（非循環）動畫，await 播畢/中斷才 resolve。委派 SpineKit（經 BaseSpine.PlayAnimation）。
     * Spine 缺失 → 立即 resolve；動畫名無效 → BaseSpine 內部 warn + 回 false，皆不 hang 呼叫端（DR-2 完成訊號鏈防 hang）。
     * @param animName 動畫名（Active/Collect/Out）
     */
    private async PlaySpineOnce(animName: string): Promise<void> {
        if (!this.m_bigWheelSpine || !this.m_bigWheelSpine.isValid) {
            return;
        }
        // BaseSpine.PlayAnimation 回 Promise<boolean>（播畢/中斷時 resolve）；此處只需等其結束，忽略結果旗標
        await this.m_bigWheelSpine.PlayAnimation(animName, undefined, false);
    }

    /**
     * @ch 播放 BigWheel 循環動畫（Idle 待機呼吸），不 await（循環動畫不等完成）。委派 SpineKit（經 BaseSpine.PlayAnimation）。
     * @param animName 動畫名（Idle）
     */
    private PlaySpineLoop(animName: string) {
        if (!this.m_bigWheelSpine || !this.m_bigWheelSpine.isValid) {
            return;
        }
        // 循環播放：isLoop=true；回傳 Promise 於首圈完成 resolve，不 await（不影響續循環）
        this.m_bigWheelSpine.PlayAnimation(animName, undefined, true);
    }

    /**
     * @ch dev-only 設定斷言（DR-3/DR-12 緩解：驗節點數量，順序語意仍須人工核對 prefab）
     */
    private DevAssertConfig() {
        if (!DEV) {
            return;
        }
        if (this.m_segmentSpriteChanges.length !== FEATURE_WHEEL_SEGMENT_COUNT) {
            warn(`FeatureWheel 設定異常：SpriteChange 數 ${this.m_segmentSpriteChanges.length} ≠ ${FEATURE_WHEEL_SEGMENT_COUNT}`);
        }
        if (this.m_segmentNodes.length !== FEATURE_WHEEL_SEGMENT_COUNT) {
            warn(`FeatureWheel 設定異常：落點節點數 ${this.m_segmentNodes.length} ≠ ${FEATURE_WHEEL_SEGMENT_COUNT}`);
        }
    }
    //#endregion 方法

    //#region 測試功能
    /**@ch 測試用：當前轉動落點索引（每次轉動 +1 循環 0~11）*/
    private m_testLandIndex = 0;
    /**@ch 測試用：當前 UI 顯示狀態（給 DIGIT_4 切換）*/
    private m_testUIShown = false;

    /**
     * @ch 註冊測試按鍵（僅 DEBUG 構建生效；正式構建零副作用）
     */
    private RegisterTestKeyCodes() {
        if (!DEBUG) {
            return;
        }
        input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
    }

    /**
     * @ch 取消註冊測試按鍵（與 RegisterTestKeyCodes 對稱，避免監聽洩漏）
     */
    private UnregisterTestKeyCodes() {
        if (!DEBUG) {
            return;
        }
        input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
    }

    /**
     * @ch 檢查測試按鍵，走真實 eventManager 事件路徑驗證 FeatureWheel 功能
     * DIGIT_1：初始化 + 設定預設輪盤資料 + 顯示 UI（一鍵就緒）
     * DIGIT_2：轉動到下一格（循環 0~11）並印出落點結果（驗證旋轉/落點演出/callback）
     * DIGIT_3：重設隨機輪盤資料（驗證 icon 與乘倍數值動態更新）
     * DIGIT_4：切換顯示/隱藏 UI
     */
    private CheckTestKeyCode(event: EventKeyboard) {
        switch (event.keyCode) {
            // case KeyCode.DIGIT_1:
            //     log('[FeatureWheel 測試] 初始化 + 設定預設資料 + 顯示 UI');
            //     // INIT 僅需非 null 物件以通過參數驗證並翻起 m_isInit；
            //     // m_gameView 在本元件未被讀取，測試以 this.node 佔位即可
            //     eventManager.Dispatch(FEATURE_WHEEL_EVENT.INIT, this.node);
            //     eventManager.Dispatch(FEATURE_WHEEL_EVENT.SET_WHEEL_DATA, GetDefaultSegments());
            //     eventManager.Dispatch(FEATURE_WHEEL_EVENT.SHOW_UI);
            //     break;

            case KeyCode.DIGIT_2: {
                const landIndex = this.m_testLandIndex % FEATURE_WHEEL_SEGMENT_COUNT;
                this.m_testLandIndex++;
                log(`[FeatureWheel 測試] 轉動到第 ${landIndex} 格`);
                eventManager.Dispatch(FEATURE_WHEEL_EVENT.PLAY_SPIN, landIndex, (result: SpinResult) => {
                    log(`[FeatureWheel 測試] 落點結果 index=${result.index} type=${result.type}`);
                });
                break;
            }

            case KeyCode.DIGIT_3:
                log('[FeatureWheel 測試] 恢復 Idle 緩轉');
                eventManager.Dispatch(FEATURE_WHEEL_EVENT.HIDE_RESULT);
                eventManager.Dispatch( FEATURE_WHEEL_EVENT.RESUME_IDLE );
                break;

            case KeyCode.DIGIT_4:
                this.m_testUIShown = !this.m_testUIShown;
                log(`[FeatureWheel 測試] 切換 UI 顯示 → ${this.m_testUIShown}`);
                eventManager.Dispatch(this.m_testUIShown ? FEATURE_WHEEL_EVENT.SHOW_UI : FEATURE_WHEEL_EVENT.HIDE_UI);
                break;
        }
    }

    /**
     * @ch 產生 12 格隨機測試資料（type 隨機）
     */
    private BuildRandomTestSegments(): SegmentDescriptor[] {
        const types = [
            FeatureWheelSegmentType.SymbolConvert,
            FeatureWheelSegmentType.Multiplier,
            FeatureWheelSegmentType.Upgrade,
            FeatureWheelSegmentType.GrandJP,
            FeatureWheelSegmentType.FreeGame,
        ];
        const segments: SegmentDescriptor[] = [];
        for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
            const type = types[Math.floor(Math.random() * types.length)];
            segments.push({ type });
        }
        return segments;
    }
    //#endregion 測試功能
}

