1	import { _decorator, Component, sp } from 'cc';
2	import Game_Define from "../Game_Define";
3	import SpineKit from 'db://astarte-framework/Component/Spine/SpineKit';
4	
5	const { ccclass, property } = _decorator;
6	
7	/**@en Basic Symbol Spine @ch 基礎Spine */
8	@ccclass('BaseSpine')
9	export class BaseSpine extends Component
10	{
11	    /**@en The spine(which will be stored in node pool) @ch 將被放置於node pool的spine*/
12	    @property( {
13	        type: sp.Skeleton,
14	        displayName: "Spine 骨骼動畫組件"
15	    } )
16	    protected m_spine: sp.Skeleton = null;
17	
18	    private _animNameCache: WeakMap<sp.SkeletonData, Set<string>> = new WeakMap();
19	
20	    /**
21	     * @ch 取得 Spine 骨骼動畫組件
22	     * @returns {sp.Skeleton} Spine 骨骼動畫組件
23	     */
24	    public get Spine(): sp.Skeleton
25	    {
26	        return this.m_spine;
27	    }
28	
29	    /**
30	     * @ch 停止所有軌道動畫並重置為 Setup Pose
31	     * @returns {void}
32	     */
33	    Stop()
34	    {
35	        if (!this.m_spine) return;
36	        this.m_spine.clearTracks();
37	        this.m_spine.setToSetupPose();
38	    }
39	
40	    /**
41	     * @ch 暫停 Spine 動畫
42	     * @returns {void}
43	     */
44	    Pause()
45	    {
46	        if (!this.m_spine) return;
47	        this.m_spine.paused = true;
48	    }
49	
50	    /**
51	     * @ch 恢復 Spine 動畫
52	     * @returns {void}
53	     */
54	    Resume()
55	    {
56	        if (!this.m_spine) return;
57	        this.m_spine.paused = false;
58	    }
59	
60	    /**
61	     * @ch 設定 Spine 的皮膚
62	     * @param {string} skinName 皮膚名稱
63	     * @param {sp.Skeleton} [target=this.m_spine] 目標 Spine 組件
64	     * @returns {void}
65	     */
66	    SetSkin(skinName: string, target = this.m_spine)
67	    {
68	        if (!target) return;
69	        target.setSkin(skinName);
70	        target.setSlotsToSetupPose();
71	    }
72	
73	    /**
74	     * @ch 設定當前節點的啟用狀態
75	     * @param {boolean} v 是否啟用
76	     * @returns {void}
77	     */
78	    SetNodeActivity(v: boolean)
79	    {
80	        this.node.active = v;
81	    }
82	
83	    /**
84	     * @ch 設定 Spine 節點的啟用狀態
85	     * @param {boolean} v 是否啟用
86	     * @returns {void}
87	     */
88	    SetSpineNodeActivity( v: boolean )
89	    {
90	        if (!this.m_spine) return;
91	        this.m_spine.node.active = v;
92	    }
93	
94	    /**
95	     * @ch 使用 Promise 控制播放 Spine 動畫
