/**
 * @ch 還原鏡頭縮放與位置
 * @param duration 動畫時長
 * @param callback 完成回調
 */
private RestoreZoom(duration: number | (() => void) = 0.5, callback?: () => void) {
    let actualDuration = typeof duration === 'number' ? duration : 0.5;
    let actualCallback = typeof duration === 'function' ? duration : callback;

    const targetNode = this.GetZoomTarget();
    if (!targetNode || !this.m_isZoomed) {
        actualCallback?.();
        return;
    }

    Tween.stopAllByTarget(targetNode);

    tween(targetNode)
        .parallel(
            tween<Node>().to(actualDuration, { position: this.m_zoomOriginalPosition }, { easing: easing.cubicOut }),
            tween<Node>().to(actualDuration, { scale: this.m_zoomOriginalScale }, { easing: easing.cubicOut })
        )
        .call(() => {
            this.m_isZoomed = false;
            actualCallback?.();
        })
        .start();
}
//#endregion Animation Methods

