78	            return;
79	        }
80	
81	        // 進場盤面效果：震動只在進場「震一下就停」（單次自停，避免轉動時持續晃很怪）；盤面往下(ZoomIn)持續整段、退場才還原。
82	        // 用 try/finally 保證 StopBoardEffect 一定執行（ZoomIn 記原始狀態，未配對盤面回不去）。
83	        this.StartBoardEffect();
84	        try
85	        {
86	            // 進場 Active（盤面下降+灰塵+光效）：一個 round 一次，落在第一次轉動前；await 播畢（Spine 缺失則立即返回不 hang）
87	            await this.PlayWheelEnter();
88	
89	            // WheelCount 迴圈：逐項「序列等待」——PlaySpin 有 m_isSpinning 重入守衛，
90	            // 未等前一次 callback 就發下一次會被靜默丟棄（FeatureWheelManager 行為，BC-2 硬約束）。
91	            for ( const wf of features )
92	            {
93	                const landIndex = wf.SlotIndex ?? 0;
94	
95	                // 防 hang：PlaySpin 對越界 landIndex 是 warn+return（不呼叫 callback）→ 若 await 會永久掛住。
96	                // 故在 dispatch 前先驗範圍，越界則 fail-loud 跳過該次（不 await）。
97	                if ( landIndex < 0 || landIndex >= FEATURE_WHEEL_SEGMENT_COUNT )
98	                {
99	                    console.warn( `[FeatureWheelShowState] SlotIndex=${landIndex} 越界 0~${FEATURE_WHEEL_SEGMENT_COUNT - 1}，跳過該次轉動` );
100	                    continue;
101	                }
102	
