540	     * @ch 播放進場 Active（一個 round 一次，落在第一次轉動前）；播畢回調。
541	     * 進場用 default skin（中間尚未落定功能）。Spine 缺失 → PlaySpineOnce 立即 resolve，不 hang 呼叫端。
542	     * @param onDone 動畫播畢回調
543	     */
544	    private async PlayEnter(onDone?: () => void) {
545	        this.SetSpineSkin(BIG_WHEEL_DEFAULT_SKIN);
546	        await this.PlaySpineOnce(BIG_WHEEL_ANIM.Active);
547	        try {
548	            onDone?.();
549	        } catch (e) {
550	            error('FeatureWheel PlayEnter onDone 失敗: ' + e);
551	        }
552	    }
