554	    /**
555	     * @ch 播放退場 Out（一個 round 一次，落在全部轉動與效果演完後）；播畢回調。
556	     * Out 的「中間功能暗掉」作用於當前落點 skin，故 setSkin(default) 放在 Out 之後（暗掉後再回 default 待 Idle）。
557	     * @param onDone 動畫播畢回調
558	     */
559	    private async PlayExit(onDone?: () => void) {
560	        await this.PlaySpineOnce(BIG_WHEEL_ANIM.Out);
561	        this.SetSpineSkin(BIG_WHEEL_DEFAULT_SKIN);
562	        try {
563	            onDone?.();
564	        } catch (e) {
565	            error('FeatureWheel PlayExit onDone 失敗: ' + e);
566	        }
567	    }
