569	    /**
570	     * @ch 設定 BigWheel skin（null/失效守衛）。委派 BaseSpine.SetSkin（內含 setSlotsToSetupPose）
571	     * @param skinName skin 名（default/Multiplier/Shift/Upgrade）
572	     */
573	    private SetSpineSkin(skinName: string) {
574	        if (this.m_bigWheelSpine && this.m_bigWheelSpine.isValid) {
575	            this.m_bigWheelSpine.SetSkin(skinName);
576	        }
577	    }
578	
579	    /**
580	     * @ch 播放 BigWheel 單次（非循環）動畫，await 播畢/中斷才 resolve。委派 SpineKit（經 BaseSpine.PlayAnimation）。
581	     * Spine 缺失 → 立即 resolve；動畫名無效 → BaseSpine 內部 warn + 回 false，皆不 hang 呼叫端（DR-2 完成訊號鏈防 hang）。
582	     * @param animName 動畫名（Active/Collect/Out）
583	     */
584	    private async PlaySpineOnce(animName: string): Promise<void> {
585	        if (!this.m_bigWheelSpine || !this.m_bigWheelSpine.isValid) {
586	            return;
587	        }
588	        // BaseSpine.PlayAnimation 回 Promise<boolean>（播畢/中斷時 resolve）；此處只需等其結束，忽略結果旗標
589	        await this.m_bigWheelSpine.PlayAnimation(animName, undefined, false);
590	    }
591	
592	    /**
593	     * @ch 播放 BigWheel 循環動畫（Idle），不 await（循環動畫不等完成）。委派 SpineKit（經 BaseSpine.PlayAnimation）。
594	     * @param animName 動畫名（Idle）
595	     * @param timeScale 播放速度；省略 → BaseSpine 預設 Game_Define.SpeedUp（快轉用），待機慢速傳 IDLE_STANDBY_TIME_SCALE
596	     */
597	    private PlaySpineLoop(animName: string, timeScale?: number) {
598	        if (!this.m_bigWheelSpine || !this.m_bigWheelSpine.isValid) {
599	            return;
600	        }
601	        // 循環播放：isLoop=true；timeScale=undefined 時 PlayAnimation 預設參數觸發=Game_Define.SpeedUp。
602	        // 回傳 Promise 於首圈完成 resolve，不 await（不影響續循環）
603	        this.m_bigWheelSpine.PlayAnimation(animName, undefined, true, timeScale);
604	    }
